// Config — editar acá si cambia el folder o el año
return [{
  json: {
    folderId: 'REPLACE_WITH_DREAN_PAUTA_FOLDER_ID',
    year: 2026,
  }
}];

const MONTHS = {
  'enero':1,'febrero':2,'marzo':3,'abril':4,'mayo':5,'junio':6,
  'julio':7,'agosto':8,'septiembre':9,'octubre':10,'noviembre':11,'diciembre':12,
};
const MONTHS_NAMES = [
  'Enero','Febrero','Marzo','Abril','Mayo','Junio',
  'Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'
];

const normalizeCategoria = (raw) => {
  const s = (raw || '').replace(/[-_]/g, ' ').trim();
  const lower = s.toLowerCase();
  if (lower.startsWith('cocina')) return 'Cocina';
  if (lower.startsWith('refriger')) return 'Refrigeración';
  if (lower.startsWith('lavado')) return 'Lavado';
  if (lower.startsWith('brand')) return 'Brand';
  if (lower.startsWith('promo')) return 'Promoción';
  if (lower.startsWith('ugc')) return 'UGC';
  return s.charAt(0).toUpperCase() + s.slice(1).toLowerCase();
};

const parseCSVLine = (line) => {
  const out = [];
  let cur = '';
  let inQ = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"' && line[i+1] === '"') { cur += '"'; i++; }
    else if (ch === '"') { inQ = !inQ; }
    else if (ch === ',' && !inQ) { out.push(cur); cur = ''; }
    else { cur += ch; }
  }
  out.push(cur);
  return out.map(c => c.trim());
};

const parseCurrency = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const s = String(v).trim();
  if (s === '-' || s === '$-' || s === '$ -' || s === '$0' || s === '$ 0') return 0;
  const cleaned = s.replace(/[\s$]/g, '').replace(/\./g, '').replace(',', '.');
  const n = Number(cleaned);
  return Number.isFinite(n) ? n : null;
};

const COSTO_PATTERNS = [/iibb/i, /percep/i, /cheque/i, /impuesto/i, /tech\s*fee/i, /comisi/i];
const esCosto = (formato) => formato && COSTO_PATTERNS.some(re => re.test(formato));

const SKIP_PATTERNS = [
  /^Total\s*ON$/i, /^Total\s*OFF$/i, /^Total\s*OFF\s*\/\s*ON$/i,
  /^Total$/i, /^Total\s/i, /^Subtotal/i,
  /Vs\s*Forecast/i, /^Forecast$/i, /^Dif$/i, /Diferencia/i,
  /^FX$/i, /^Tipo\s*de\s*cambio/i,
  /^Sin\s*formato/i,
];
const esPct = (v) => v && /^\d+[.,]?\d*\s*%$/.test(v);
const esSkip = (sistema, formato, rol) => {
  for (const f of [rol, sistema, formato]) {
    if (!f) continue;
    if (SKIP_PATTERNS.some(re => re.test(f))) return true;
  }
  if (esCosto(formato)) return false;
  const isDash = v => !v || /^\$?\s*-+\s*$/.test(v);
  if (isDash(sistema) && isDash(formato)) return true;
  if (sistema && /^\$\s*[\d.,]+$/.test(sistema)) return true;
  if (esPct(sistema)) return true;
  return false;
};

const config = $('Set Config').first().json;
const YEAR = config.year || 2026;

const rows = [];
const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binaryKey = Object.keys(item.binary || {})[0];
  if (!binaryKey) continue;
  const bin = item.binary[binaryKey];
  const filename = bin.fileName || item.json.name || '';

  const m = filename.match(/^([A-Za-zÁÉÍÓÚáéíóúñÑ]+)[-_\s]+(.+?)\.csv$/i);
  if (!m) continue;
  const campania = normalizeCategoria(m[2]);

  const buffer = await this.helpers.getBinaryDataBuffer(i, binaryKey);
  const csvText = buffer.toString('utf-8');
  const allLines = csvText.split(/\r?\n/);

  let headerIdx = -1;
  let headers = [];
  for (let r = 0; r < Math.min(allLines.length, 30); r++) {
    const cells = parseCSVLine(allLines[r]);
    const hasRol = cells.some(c => /Rol\s*Of\s*Comms/i.test(c));
    const hasSis = cells.some(c => /^Sistema$/i.test(c));
    const hasFmt = cells.some(c => /Formato/i.test(c));
    if (hasRol || (hasSis && hasFmt)) {
      headerIdx = r;
      headers = cells;
      break;
    }
  }
  if (headerIdx < 0) continue;

  const idx = (...names) => {
    for (const n of names) {
      const k = headers.findIndex(h => h.toLowerCase() === n.toLowerCase());
      if (k >= 0) return k;
    }
    return -1;
  };

  const iRol   = idx('Rol Of Comms', 'Rol', 'Rol of Comms');
  const iTouch = idx('TouchPoint', 'Touchpoint', 'Touch Point');
  const iSis   = idx('Sistema', 'Plataforma', 'Platform');
  const iFmt   = idx('Formato & Channel', 'Formato', 'Formato y Channel', 'Format');

  const monthCols = [];
  for (let mn = 1; mn <= 12; mn++) {
    const mesName = MONTHS_NAMES[mn - 1];
    const k = headers.findIndex(h => h.toLowerCase() === mesName.toLowerCase());
    if (k >= 0) monthCols.push({ mesNum: mn, idx: k });
  }
  const iInvGen = idx('Inversion', 'Inversión', 'Inv', 'Invertido', 'Total');
  if (monthCols.length === 0 && iInvGen < 0) continue;

  let fallbackFecha = null;
  if (monthCols.length === 0) {
    const mesRaw = m[1].toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
    const mesNum = MONTHS[mesRaw];
    if (!mesNum) continue;
    fallbackFecha = `${YEAR}-${String(mesNum).padStart(2,'0')}-01`;
  }

  for (let r = headerIdx + 1; r < allLines.length; r++) {
    const line = allLines[r];
    if (!line || !line.trim()) continue;
    const cols = parseCSVLine(line);
    if (cols.length === 0) continue;

    const rol     = iRol   >= 0 ? cols[iRol]   : '';
    const touch   = iTouch >= 0 ? cols[iTouch] : '';
    let   sistema = iSis   >= 0 ? cols[iSis]   : '';
    const formato = iFmt   >= 0 ? cols[iFmt]   : '';

    if (esSkip(sistema, formato, rol)) continue;
    if (!sistema && !formato) continue;

    const isCost = esCosto(formato);
    if (isCost && esPct(sistema)) sistema = '';

    const pushRow = (fecha, inversion) => {
      rows.push({
        fecha,
        campania,
        rol: rol || null,
        touchpoint: touch || null,
        sistema: sistema || null,
        formato: formato || null,
        inversion,
        tipo: isCost ? 'costo' : 'media',
      });
    };

    if (monthCols.length > 0) {
      for (const mc of monthCols) {
        const inv = parseCurrency(cols[mc.idx]);
        if (inv === null || inv === 0) continue;
        const fecha = `${YEAR}-${String(mc.mesNum).padStart(2,'0')}-01`;
        pushRow(fecha, inv);
      }
    } else {
      const inv = parseCurrency(cols[iInvGen]);
      if (inv === null || inv === 0) continue;
      pushRow(fallbackFecha, inv);
    }
  }
}

const agg = new Map();
for (const r of rows) {
  const key = [r.fecha, r.campania, r.rol || '', r.sistema || '', r.formato || '', r.tipo].join('|');
  const prev = agg.get(key);
  if (prev) {
    prev.inversion += r.inversion;
    if (r.touchpoint && prev.touchpoint && !prev.touchpoint.includes(r.touchpoint)) {
      prev.touchpoint = prev.touchpoint + ' / ' + r.touchpoint;
    } else if (r.touchpoint && !prev.touchpoint) {
      prev.touchpoint = r.touchpoint;
    }
  } else {
    agg.set(key, { ...r });
  }
}

return Array.from(agg.values()).map(j => ({ json: j }));
